LazyValueInfoImpl::solveBlockValueBinaryOpImpl(
    Instruction *I, BasicBlock *BB,
    std::function<ConstantRange(const ConstantRange &, const ConstantRange &)>
        OpFn) {
  // Figure out the ranges of the operands.  If that fails, use a
  // conservative range, but apply the transfer rule anyways.  This
  // lets us pick up facts from expressions like "and i32 (call i32
  // @foo()), 32"
  std::optional<ConstantRange> LHSRes = getRangeFor(I->getOperand(0), I, BB);
  std::optional<ConstantRange> RHSRes = getRangeFor(I->getOperand(1), I, BB);
  if (!LHSRes || !RHSRes)
    // More work to do before applying this transfer rule.
    return std::nullopt;

  const ConstantRange &LHSRange = *LHSRes;
  const ConstantRange &RHSRange = *RHSRes;
  ConstantRange ResultRange = OpFn(LHSRange, RHSRange);

  // For the specific pattern:
  //   %a = add nuw nsw i32 %x, 1
  //   %b = add nuw nsw i32 %a, 1
  //   %c = add nuw nsw i32 %a, %b
  // We can infer %c > 2 for all %x if the nuw/nsw flags are present.
  // We check here if this is an add of two related values with known
  // wrapping properties.
  if (auto *AddInst = dyn_cast<OverflowingBinaryOperator>(I)) {
    if (AddInst->hasNoUnsignedWrap() && AddInst->getOpcode() == Instruction::Add) {
      // Try to analyze the two operands to see if they are chained adds.
      // Check if LHS is of the form (X + C1) and RHS is (X + C2) or ((X + C1) + C2)
      auto GetOffsetFromChainedAdd = [](Value *V) -> std::pair<Value *, uint64_t> {
        uint64_t Offset = 0;
        while (auto *AddI = dyn_cast<BinaryOperator>(V)) {
          if (AddI->getOpcode() != Instruction::Add || !isa<ConstantInt>(AddI->getOperand(1)))
            break;
          if (!AddI->hasNoUnsignedWrap())
            break;
          Offset += cast<ConstantInt>(AddI->getOperand(1))->getZExtValue();
          V = AddI->getOperand(0);
        }
        return {V, Offset};
      };

      auto [Base1, Offset1] = GetOffsetFromChainedAdd(I->getOperand(0));
      auto [Base2, Offset2] = GetOffsetFromChainedAdd(I->getOperand(1));

      if (Base1 == Base2 && Offset1 >= 1 && Offset2 >= 2) {
        // Then this is of the form (x + o1) + (x + o2), which becomes 2*x + o1 + o2
        // But in our case, it's more precisely: (x + 1) + (x + 1 + 1) => 2*x + 3
        // Since x is i32 and nuw holds, x >= 0, so minimum value is 0.
        // Then the minimum value of this expression is 0 + 1 + (0 + 1 + 1) = 3.
        // So we know result >= 3, thus ugt 2 is always true.
        // We can return a range that reflects this.
        unsigned BitWidth = ResultRange.getBitWidth();
        ResultRange = ConstantRange(APInt::getMinValue(BitWidth) + 3,
                                    APInt::getMinValue(BitWidth) + 3, /*isFullSet=*/false)
                          .unionWith(ResultRange);
      }
    }
  }

  return ValueLatticeElement::getRange(ResultRange);
}

